void IAnchor.Add(AnchorLink anchorLink)
        {
            if (!_links.Where(l => !string.IsNullOrEmpty(l.Href))
                   .Select(l => l.Href)
                   .Contains(anchorLink.Href))
            {
                _links.Add(anchorLink);
            }
        }

internal void Add(AnchorLink anchorLink)
        {
            if (!_links.Where(l => !string.IsNullOrEmpty(l.Href))
                .Select(l => l.Href)
                .Contains(anchorLink.Href))
            {
                _links.Add(anchorLink);
            }
        }

internal async Task<DomRect> GetHrefDom(bool forced = false)
        {
            DomRect domRect = null;
            if (forced || _hrefDomExist)
            {
                domRect = await JsInvokeAsync<DomRect>(JSInteropConstants.GetBoundingClientRect, "#" + Href.Split('#')[1]);
            }
            return domRect;
        }

private void SetActiveItem(AutoCompleteOption item)
        {
            this._activeValue = item == null ? default(TOption) : item.Value;
            if (OnActiveChange.HasDelegate) OnActiveChange.InvokeAsync(item);
            StateHasChanged();
        }

protected override void OnInitialized()
        {
            base.OnInitialized();

            ClassMapper
                .Add(_prefixCls)
                .If($"{_prefixCls}-rtl", () => RTL);

            _popoverClassMapper
                .Add($"{_prefixCls}-popover")
                .If($"{_prefixCls}-popover-rtl", () => RTL);
        }

protected void SetClass()
        {
            string prefixCls = "ant-back-top";
            ClassMapper.Add(prefixCls);

            BackTopContentClassMapper
                .If($"{prefixCls}-content", () => ChildContent == null)
                .If("ant-fade ant-fade-leave ant-fade-leave-active", () => !_visible)
                .If("ant-fade ant-fade-enter ant-fade-enter-active", () => _visible)
                ;

            BackTopIconClassMapper.Add($"{prefixCls}-icon");
        }

private void SetClassMap()
        {
            var prefixName = "ant-ribbon";
            ClassMapper.Clear()
                .Add(prefixName)
                .Add($"{prefixName}-placement-{Placement}")
                .If($"{prefixName}-rtl", () => RTL)
                .If($"{prefixName}-color-{PresetColor}", () => PresetColor != null)
                ;
        }

public void AppendElement(int sequence, string elementName)
    {
        if (_itemsInUse == _items.Length)
        {
            GrowBuffer(_items.Length * 2);
        }

        _items[_itemsInUse++] = new RenderTreeFrame
        {
            SequenceField = sequence,
            FrameTypeField = RenderTreeFrameType.Element,
            ElementNameField = elementName,
        };
    }

