internal async Task DragEndedAsync()
    {
        if (_dragOperationIsInProgress)
        {
            _dragOperationIsInProgress = false;
            if (Container is not null)
            {
                await Container.CancelTransaction();
            }
        }
        else
        {
            await OnDragEnded.InvokeAsync(Item);
        }
    }

public MudExitPrompt()
    {
        using var registerScope = CreateRegisterScope();
        registerScope.RegisterParameter<bool>(nameof(Disabled))
            .WithParameter(() => Disabled)
            .WithChangeHandler(args => !args.Value ? EnableAsync() : DisableAsync());
        registerScope.RegisterParameter<string?>(nameof(Text))
            .WithParameter(() => Text)
            .WithChangeHandler(SetTextAsync);
    }

public MudExpansionPanel()
        {
            using var registerScope = CreateRegisterScope();
            _expandedState = registerScope.RegisterParameter<bool>(nameof(Expanded))
                .WithParameter(() => Expanded)
                .WithEventCallback(() => ExpandedChanged)
                .WithChangeHandler(OnExpandedParameterChangedAsync);
        }

internal async Task AddPanelAsync(MudExpansionPanel panel)
        {
            if (!MultiExpansion && _panels.Any(p => p._expandedState.Value))
            {
                await panel.CollapseAsync();
            }

            _panels.Add(panel);
        }

public Task UpdateAllAsync()
        {
            MudExpansionPanel? last = null;
            foreach (var panel in _panels)
            {
                if (last is not null)
                {
                    last.NextPanelExpanded = panel._expandedState.Value;
                }

                last = panel;
            }
            StateHasChanged();

            return Task.CompletedTask;
        }

public MudFileUpload()
        {
            using var registerScope = CreateRegisterScope();
            _filesState = registerScope.RegisterParameter<T?>(nameof(Files))
                .WithParameter(() => Files)
                .WithEventCallback(() => FilesChanged);
            _draggingState = registerScope.RegisterParameter<bool>(nameof(Dragging))
                .WithParameter(() => Dragging)
                .WithEventCallback(() => DraggingChanged);
        }
